```swift
import SwiftUI

struct ContentView: View {
    @State private var colors: [Color] = (0..<10).map { _ in
        Color(
            red: .random(in: 0...1),
            green: .random(in: 0...1),
            blue: .random(in: 0...1)
        )
    }

    let columns = [
        GridItem(.flexible()),
        GridItem(.flexible())
    ]

    var body: some View {
        ScrollView {
            LazyVGrid(columns: columns, spacing: 20) {
                ForEach(colors.indices, id: \.self) { index in
                    RoundedRectangle(cornerRadius: 10)
                        .fill(colors[index])
                        .frame(height: 100)
                        .overlay(
                            Text("\(index + 1)")
                                .font(.largeTitle)
                                .foregroundColor(.white)
                        )
                        .onDrag {
                            NSItemProvider(object: String(index) as NSString)
                        }
                        .onDrop(of: [.plainText], delegate: DropViewDelegate(
                            destinationIndex: index,
                            colors: $colors
                        ))
                }
            }
            .padding()
        }
    }
}

struct DropViewDelegate: DropDelegate {
    let destinationIndex: Int
    @Binding var colors: [Color]

    func performDrop(info: DropInfo) -> Bool {
        guard let itemProvider = info.itemProviders(for: [.plainText]).first,
              let item = itemProvider as? NSItemProvider else {
            return false
        }

        item.loadItem(forTypeIdentifier: "public.plain-text", options: nil) { data, _ in
            DispatchQueue.main.async {
                if let data = data as? Data,
                   let indexString = String(data: data, encoding: .utf8),
                   let sourceIndex = Int(indexString) {

                    let color = colors.remove(at: sourceIndex)
                    colors.insert(color, at: destinationIndex)
                }
            }
        }

        return true
    }
}

@main
struct DragDropGridApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}
